chain(A, B, C):
  for iterable in [A, B, C]:
    for element in iterable:
      yield element

chain.from_iterable([[A, B], [C, D]]):
  for iterable in [[A, B], [C, D]]:
    for element in iterable:
      yield element

product(A, B):
  # equivalent to:
  for a in A:
    for b in B:
      yield (a, b)

product(A, repeat=2):
  # equivalent to:
  for a1 in A:
    for a2 in A:
      yield (a1, a2)

groupby(iterable, key):
  current_key = None
  current_group = []
  for item in iterable:
    k = key(item)
    if k != current_key:
      if current_group:
        yield current_key, iter(current_group)
      current_key = k
      current_group = [item]
    else:
      current_group.append(item)
  yield current_key, iter(current_group)

