from functools import lru_cache, cache

# Classic example: Fibonacci
@lru_cache(maxsize=128)
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

print(fibonacci(50))  # 12586269025 (instant, without cache would be very slow)

# Cache info and management
print(fibonacci.cache_info())
# CacheInfo(hits=48, misses=51, maxsize=128, currsize=51)

fibonacci.cache_clear()  # clear the cache

# typed=True: different types cached separately
@lru_cache(maxsize=32, typed=True)
def process(value):
    print(f"Computing for {value!r} (type={type(value).__name__})")
    return value * 2

process(3)    # prints "Computing for 3 (type=int)"
process(3.0)  # prints "Computing for 3.0 (type=float)" -- separate cache entry
process(3)    # cache hit, no print

# Python 3.9+ shorthand
@cache  # equivalent to lru_cache(maxsize=None)
def factorial(n):
    return n * factorial(n - 1) if n else 1

print(factorial(10))  # 3628800

# Practical: expensive computation caching
@lru_cache(maxsize=256)
def fetch_user_permissions(user_id: int, role: str) -> set:
    # Simulating expensive DB query
    print(f"DB query for user {user_id}, role {role}")
    return {f"perm_{i}" for i in range(5)}

fetch_user_permissions(1, 'admin')  # DB query
fetch_user_permissions(1, 'admin')  # cache hit
fetch_user_permissions(1, 'user')   # DB query (different args)

