from functools import singledispatch, singledispatchmethod

@singledispatch
def format_value(value):
    """Default handler for unknown types."""
    return f"Unknown: {value!r}"

@format_value.register(int)
def _(value):
    return f"Integer: {value:,}"

@format_value.register(float)
def _(value):
    return f"Float: {value:.2f}"

@format_value.register(str)
def _(value):
    return f"String: '{value}'"

@format_value.register(list)
def _(value):
    return f"List[{len(value)} items]: {value}"

# Type annotations style (Python 3.7+)
@format_value.register
def _(value: dict):
    return f"Dict[{len(value)} keys]: {list(value.keys())}"

print(format_value(42))           # Integer: 42
print(format_value(3.14159))      # Float: 3.14
print(format_value("hello"))      # String: 'hello'
print(format_value([1, 2, 3]))    # List[3 items]: [1, 2, 3]
print(format_value({"a": 1}))     # Dict[1 keys]: ['a']
print(format_value(None))         # Unknown: None

# singledispatchmethod for classes
class Serializer:
    @singledispatchmethod
    def serialize(self, value):
        raise TypeError(f"Cannot serialize {type(value)}")

    @serialize.register(int)
    @serialize.register(float)
    def _(self, value):
        return str(value)

    @serialize.register(str)
    def _(self, value):
        return f'"{value}"'

s = Serializer()
print(s.serialize(42))       # '42'
print(s.serialize("hello"))  # '"hello"'

